gold_sql:
SELECT SUM(amount_kzt) AS total_kzt
FROM afm.transactions_nl_view
WHERE amount_kzt IS NOT NULL;

SELECT AVG(amount_kzt) AS avg_kzt
FROM afm.transactions_nl_view
WHERE amount_kzt IS NOT NULL;

SELECT MAX(amount_kzt) AS max_amount, MIN(amount_kzt) AS min_amount
FROM afm.transactions_nl_view
WHERE amount_kzt IS NOT NULL;

SELECT PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY amount_kzt) AS median_amount
FROM afm.transactions_nl_view
WHERE amount_kzt IS NOT NULL;

SELECT COUNT(DISTINCT payer_name) AS unique_payers
FROM afm.transactions_nl_view
WHERE payer_name IS NOT NULL;

SELECT COUNT(DISTINCT receiver_name) AS unique_receivers
FROM afm.transactions_nl_view
WHERE receiver_name IS NOT NULL;

SELECT COUNT(DISTINCT account_iban) AS total_statements
FROM afm.transactions_nl_view
WHERE account_iban IS NOT NULL;

SELECT MIN(operation_date) AS earliest, MAX(operation_date) AS latest
FROM afm.transactions_nl_view
WHERE operation_date IS NOT NULL;

SELECT COUNT(*) AS no_date_count
FROM afm.transactions_nl_view
WHERE operation_date IS NULL;

SELECT COUNT(*) AS pre_2024_count
FROM afm.transactions_nl_view
WHERE operation_date < '2024-01-01';
